Have found an issue in the remove method
Run this test to reproduce

it.only('should remove nodes', () => {
    const root = new BinarySearchTreeNode(8);
    root.insert(3);
    root.insert(6);
    root.remove(3);
    root.remove(6);
    expect(root.right).toBeNull();
    expect(root.left).toBeNull();
  });
